  .toggle-row { display: flex; align-items: center; justify-content: space-between; cursor: pointer; user-select: none; }
  .toggle-label { display: block; font-size: 11px; font-weight: 500; letter-spacing: 0.1em; text-transform: uppercase; color: var(--muted); margin: 0; cursor: pointer; }
  .toggle-desc { font-size: 12px; color: var(--muted); opacity: 0.7; margin-top: 2px; }
